17	// RBTDRP — pristine-lifecycle fixture for theurge release qualification
18	//
19	// Case 1 (marshal-zero-attestation) is the entry gate for `rbw-tP`. It asserts
20	// that the working tree was just zeroed by `rbw-MZ` (rblm_zero) — five
21	// violation classes are checked and ALL surfaced in one aggregated diagnostic.
22	// Failure short-circuits subsequent cases via the per-fixture fail_fast switch.
23	
24	use std::path::{Path, PathBuf};
25	use std::process::Command;
26	
27	use crate::case;
28	use crate::rbtdrc_crucible::rbtdrc_with_ctx;
29	use crate::rbtdre_engine::{rbtdre_Section, rbtdre_Verdict};
30	use crate::rbtdri_invocation::{rbtdri_invoke_global, rbtdri_read_burv_fact, rbtdri_Context};
31	use crate::rbtdrm_manifest::{
32	    RBTDRM_COLOPHON_DEPOT_LEVY, RBTDRM_COLOPHON_DEPOT_LIST, RBTDRM_COLOPHON_DEPOT_UNMAKE,
33	    RBTDRM_COLOPHON_GOV_FORFEIT, RBTDRM_COLOPHON_GOV_LIST_SAS, RBTDRM_COLOPHON_GOV_MANTLE,
34	};
35	
36	/// RBRR field names referenced by the pristine-lifecycle fixture. Field
37	/// identifiers extracted as consts so the blank-field array and the
38	/// throwaway-prefix install helper share a single definition site.
39	const RBTDRP_FIELD_RBRR_CLOUD_PREFIX: &str = "RBRR_CLOUD_PREFIX";
40	const RBTDRP_FIELD_RBRR_RUNTIME_PREFIX: &str = "RBRR_RUNTIME_PREFIX";
41	const RBTDRP_FIELD_RBRR_DEPOT_PROJECT_ID: &str = "RBRR_DEPOT_PROJECT_ID";
42	
43	/// Site-specific RBRR fields that rblm_zero blanks. These five fields define
44	/// the depot-bound site identity; an empty value is the post-marshal-zero
45	/// invariant.
46	const RBTDRP_RBRR_BLANK_FIELDS: &[&str] = &[
47	    RBTDRP_FIELD_RBRR_DEPOT_PROJECT_ID,
48	    "RBRR_GAR_REPOSITORY",
49	    "RBRR_GCB_POOL_STEM",
50	    RBTDRP_FIELD_RBRR_CLOUD_PREFIX,
51	    RBTDRP_FIELD_RBRR_RUNTIME_PREFIX,
52	];
53	
54	/// Throwaway RBRR prefix values stamped into rbrr.env by
55	/// `rbtdrp_install_throwaway_prefixes`. Pristine-lifecycle cases that need
56	/// non-blank prefixes (depot/governor/retriever/director lifecycle) call the
57	/// helper to install these values; the marker shape distinguishes throwaway
58	/// from operator-chosen canonical values.
59	pub(crate) const RBTDRP_THROWAWAY_CLOUD_PREFIX: &str = "prlc-";
60	pub(crate) const RBTDRP_THROWAWAY_RUNTIME_PREFIX: &str = "prlr-";
61	
62	/// Throwaway depot monikers used by cases 2 and 3. Distinct values keep the
63	/// two cases' depots separable when both run in the same fixture pass.
64	const RBTDRP_DEPOT_MONIKER_LIFECYCLE: &str = "pristq01";
65	const RBTDRP_DEPOT_MONIKER_GOVERNOR: &str = "pristg01";
66	
67	/// Fact-file names emitted by the rbgp tabtargets (mirror of bash consts in
68	/// rbgc_Constants.sh). Cases read these values from the BURV output dir of
69	/// the producing invocation.
70	const RBTDRP_FACT_DEPOT_PROJECT_ID: &str = "rbgp_fact_depot_project_id";
71	const RBTDRP_FACT_GOVERNOR_SA_EMAIL: &str = "rbgp_fact_governor_sa_email";
72	
73	/// BURE confirmation override (mirrors buc_command.sh): when set to "skip",
74	/// `buc_require` accepts the operation without interactive prompt.
75	const RBTDRP_BURE_CONFIRM_KEY: &str = "BURE_CONFIRM";
76	const RBTDRP_BURE_CONFIRM_SKIP: &str = "skip";
77	
78	/// `DELETE_REQUESTED` lifecycle state — appears in `rbgp_depot_list` output
79	/// after a soft-delete, used by case 2 to relax the post-unmake assertion.
80	const RBTDRP_DELETE_REQUESTED: &str = "DELETE_REQUESTED";
81	
82	/// Roles whose RBRA credential files rblm_zero deletes.
83	const RBTDRP_RBRA_ROLES: &[&str] = &["governor", "director", "retriever", "assay"];
84	
85	/// Nameplate hallmark fields rblm_zero blanks.
86	const RBTDRP_RBRN_BLANK_FIELDS: &[&str] = &["RBRN_SENTRY_HALLMARK", "RBRN_BOTTLE_HALLMARK"];
87	
88	/// File-relative constants matching rbbc_constants.sh / rbcc_Constants.sh.
89	const RBTDRP_DOT_DIR: &str = ".rbk";
90	const RBTDRP_RBRR_FILE: &str = ".rbk/rbrr.env";
91	const RBTDRP_RBRA_FILE: &str = "rbra.env";
92	const RBTDRP_RBRN_FILE: &str = "rbrn.env";
93	const RBTDRP_RBRV_FILE: &str = "rbrv.env";
94	
95	// ── Helpers ──────────────────────────────────────────────────
96	
97	/// Read an env file and return the value for `key`, or None if the key is
98	/// absent. The bash regime files use `KEY=value` lines (unquoted); comment
99	/// and blank lines are skipped. The trailing newline is stripped from value.
100	fn rbtdrp_read_env_value(path: &Path, key: &str) -> Option<String> {
101	    let content = std::fs::read_to_string(path).ok()?;
102	    let prefix = format!("{}=", key);
103	    for line in content.lines() {
104	        let trimmed = line.trim_start();
105	        if trimmed.starts_with('#') {
106	            continue;
107	        }
108	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
109	            return Some(rest.to_string());
110	        }
111	    }
112	    None
113	}
114	
115	/// Resolve a path that may be absolute or relative-to-project-root.
116	fn rbtdrp_resolve(root: &Path, raw: &str) -> PathBuf {
117	    if Path::new(raw).is_absolute() {
118	        PathBuf::from(raw)
119	    } else {
120	        root.join(raw)
121	    }
122	}
123	
124	/// Class A — working tree clean (`git status --porcelain` empty).
125	fn rbtdrp_check_tree_clean(root: &Path, violations: &mut Vec<String>) {
126	    match Command::new("git")
127	        .args(["status", "--porcelain"])
128	        .current_dir(root)
129	        .output()
130	    {
131	        Ok(out) if out.status.success() => {
132	            let stdout = String::from_utf8_lossy(&out.stdout);
133	            let trimmed = stdout.trim();
134	            if !trimmed.is_empty() {
135	                violations.push(format!(
136	                    "working tree not clean — uncommitted changes:\n{}",
137	                    trimmed
138	                ));
139	            }
140	        }
141	        Ok(out) => violations.push(format!(
142	            "git status --porcelain failed (exit {}): {}",
143	            out.status.code().unwrap_or(-1),
144	            String::from_utf8_lossy(&out.stderr).trim()
145	        )),
146	        Err(e) => violations.push(format!("git status invocation failed: {}", e)),
147	    }
148	}
149	
150	/// Class B — five site-specific RBRR fields are blank.
151	fn rbtdrp_check_rbrr_fields(rbrr: &Path, violations: &mut Vec<String>) {
152	    for field in RBTDRP_RBRR_BLANK_FIELDS {
153	        if let Some(value) = rbtdrp_read_env_value(rbrr, field) {
154	            if !value.is_empty() {
155	                violations.push(format!(
156	                    "RBRR field non-blank: {}={} (in {})",
157	                    field,
158	                    value,
159	                    rbrr.display()
160	                ));
161	            }
162	        }
163	    }
164	}
165	
166	/// Class C — no RBRA credential files at the four role paths.
167	fn rbtdrp_check_rbra_files(root: &Path, secrets_dir: &str, violations: &mut Vec<String>) {
168	    if secrets_dir.is_empty() {
169	        violations.push(
170	            "RBRR_SECRETS_DIR is blank — cannot resolve credential paths".to_string(),
171	        );
172	        return;
173	    }
174	    let secrets = rbtdrp_resolve(root, secrets_dir);
175	    for role in RBTDRP_RBRA_ROLES {
176	        let path = secrets.join(role).join(RBTDRP_RBRA_FILE);
177	        if path.exists() {
178	            violations.push(format!("RBRA credential present: {}", path.display()));
179	        }
180	    }
181	}
182	
183	/// Class D — every nameplate's RBRN_SENTRY_HALLMARK and RBRN_BOTTLE_HALLMARK
184	/// is blank.
185	fn rbtdrp_check_nameplate_hallmarks(root: &Path, violations: &mut Vec<String>) {
186	    let dot_dir = root.join(RBTDRP_DOT_DIR);
187	    let entries = match std::fs::read_dir(&dot_dir) {
188	        Ok(e) => e,
189	        Err(e) => {
190	            violations.push(format!("cannot read {}: {}", dot_dir.display(), e));
191	            return;
192	        }
193	    };
194	    for entry in entries.flatten() {
195	        let np_dir = entry.path();
196	        if !np_dir.is_dir() {
197	            continue;
198	        }
199	        let rbrn = np_dir.join(RBTDRP_RBRN_FILE);
200	        if !rbrn.exists() {
201	            continue;
202	        }
203	        for field in RBTDRP_RBRN_BLANK_FIELDS {
204	            if let Some(value) = rbtdrp_read_env_value(&rbrn, field) {
205	                if !value.is_empty() {
206	                    violations.push(format!(
207	                        "nameplate hallmark non-blank: {}={} (in {})",
208	                        field,
209	                        value,
210	                        rbrn.display()
211	                    ));
212	                }
213	            }
214	        }
215	    }
216	}
217	
218	/// Class E — every vessel rbrv.env has RBRV_RELIQUARY blank and every
219	/// RBRV_IMAGE_*_ANCHOR field blank.
220	fn rbtdrp_check_vessel_depot_fields(
221	    root: &Path,
222	    vessel_dir: &str,
223	    violations: &mut Vec<String>,
224	) {
225	    if vessel_dir.is_empty() {
226	        violations.push("RBRR_VESSEL_DIR is blank — cannot scan vessels".to_string());
227	        return;
228	    }
229	    let vroot = rbtdrp_resolve(root, vessel_dir);
230	    let entries = match std::fs::read_dir(&vroot) {
231	        Ok(e) => e,
232	        Err(e) => {
233	            violations.push(format!("cannot read {}: {}", vroot.display(), e));
234	            return;
235	        }
236	    };
237	    for entry in entries.flatten() {
238	        let v_dir = entry.path();
239	        if !v_dir.is_dir() {
240	            continue;
241	        }
242	        let rbrv = v_dir.join(RBTDRP_RBRV_FILE);
243	        if !rbrv.exists() {
244	            continue;
245	        }
246	        rbtdrp_scan_rbrv_file(&rbrv, violations);
247	    }
248	}
249	
250	/// Scan a single rbrv.env for non-blank RBRV_RELIQUARY and RBRV_IMAGE_*_ANCHOR
251	/// fields.
252	fn rbtdrp_scan_rbrv_file(rbrv: &Path, violations: &mut Vec<String>) {
253	    let content = match std::fs::read_to_string(rbrv) {
254	        Ok(c) => c,
255	        Err(e) => {
256	            violations.push(format!("cannot read {}: {}", rbrv.display(), e));
257	            return;
258	        }
259	    };
260	    for line in content.lines() {
261	        let trimmed = line.trim_start();
262	        if trimmed.starts_with('#') {
263	            continue;
264	        }
265	        let (key, value) = match trimmed.split_once('=') {
266	            Some(kv) => kv,
267	            None => continue,
268	        };
269	        let is_reliquary = key == "RBRV_RELIQUARY";
270	        let is_anchor = key.starts_with("RBRV_IMAGE_") && key.ends_with("_ANCHOR");
271	        if (is_reliquary || is_anchor) && !value.is_empty() {
272	            violations.push(format!(
273	                "vessel depot-scoped field non-blank: {}={} (in {})",
274	                key,
275	                value,
276	                rbrv.display()
277	            ));
278	        }
279	    }
280	}
281	
282	// ── Env-file rewrite + git commit helpers ────────────────────
283	
284	/// Rewrite each line in `content` whose key matches an entry in `pairs`
285	/// (matched as `KEY=`) to `KEY=value`. Lines whose keys are not in `pairs`
286	/// pass through unchanged. The trailing-newline shape is preserved.
287	fn rbtdrp_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
288	    let mut result: String = content
289	        .lines()
290	        .map(|line| {
291	            for (key, value) in pairs {
292	                let assign = format!("{}=", key);
293	                if line.starts_with(&assign) {
294	                    return format!("{}{}", assign, value);
295	                }
296	            }
297	            line.to_string()
298	        })
299	        .collect::<Vec<_>>()
300	        .join("\n");
301	    if content.ends_with('\n') {
302	        result.push('\n');
303	    }
304	    result
305	}
306	
307	/// `git add <file> && git commit -m <message>` from `root`. Bubbles the
308	/// underlying stderr on either step's failure.
309	fn rbtdrp_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
310	    let add = Command::new("git")
311	        .args(["add", file])
312	        .current_dir(root)
313	        .output()
314	        .map_err(|e| format!("rbtdrp: git add invocation failed: {}", e))?;
315	    if !add.status.success() {
316	        return Err(format!(
317	            "rbtdrp: git add failed (exit {}): {}",
318	            add.status.code().unwrap_or(-1),
319	            String::from_utf8_lossy(&add.stderr).trim()
320	        ));
321	    }
322	
323	    let commit = Command::new("git")
324	        .args(["commit", "-m", message])
325	        .current_dir(root)
326	        .output()
327	        .map_err(|e| format!("rbtdrp: git commit invocation failed: {}", e))?;
328	    if !commit.status.success() {
329	        return Err(format!(
330	            "rbtdrp: git commit failed (exit {}): {}",
331	            commit.status.code().unwrap_or(-1),
332	            String::from_utf8_lossy(&commit.stderr).trim()
333	        ));
334	    }
335	
336	    Ok(())
337	}
338	
339	// ── Throwaway-prefix install ─────────────────────────────────
340	
341	/// Idempotently install throwaway RBRR prefixes into `.rbk/rbrr.env`.
342	///
343	/// Pristine-lifecycle cases that need non-blank prefixes (depot/governor/
344	/// retriever/director lifecycle) call this as their first step. The helper
345	/// reads current values; if `RBRR_CLOUD_PREFIX` and `RBRR_RUNTIME_PREFIX`
346	/// already match the throwaway markers, returns `Ok(())` with no side
347	/// effect. Otherwise rewrites both lines in place, then `git add` +
348	/// `git commit` the change. One commit per fixture run regardless of which
349	/// case is the first to call it.
350	///
351	/// HEAD walks off marshal-zero after the commit; recovery is `rbw-MZ`,
352	/// matching the pristine fixture's start-over-from-zero failure mode.
353	pub(crate) fn rbtdrp_install_throwaway_prefixes(root: &Path) -> Result<(), String> {
354	    let rbrr = root.join(RBTDRP_RBRR_FILE);
355	    let cloud = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX).unwrap_or_default();
356	    let runtime =
357	        rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
358	
359	    if cloud == RBTDRP_THROWAWAY_CLOUD_PREFIX && runtime == RBTDRP_THROWAWAY_RUNTIME_PREFIX {
360	        return Ok(());
361	    }
362	
363	    let content = std::fs::read_to_string(&rbrr)
364	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
365	    let new_content = rbtdrp_replace_env_fields(
366	        &content,
367	        &[
368	            (RBTDRP_FIELD_RBRR_CLOUD_PREFIX, RBTDRP_THROWAWAY_CLOUD_PREFIX),
369	            (
370	                RBTDRP_FIELD_RBRR_RUNTIME_PREFIX,
371	                RBTDRP_THROWAWAY_RUNTIME_PREFIX,
372	            ),
373	        ],
374	    );
375	    std::fs::write(&rbrr, &new_content)
376	        .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
377	
378	    let commit_msg = format!(
379	        "pristine-lifecycle fixture: install throwaway RBRR prefixes ({}/{})",
380	        RBTDRP_THROWAWAY_CLOUD_PREFIX, RBTDRP_THROWAWAY_RUNTIME_PREFIX
381	    );
382	    rbtdrp_git_add_and_commit(root, RBTDRP_RBRR_FILE, &commit_msg)
383	}
384	
385	/// Set `RBRR_DEPOT_PROJECT_ID` in rbrr.env to `project_id` and commit. Used
386	/// by case 3 to satisfy `rbgp_governor_mantle`'s precondition that the
387	/// depot project is named in the regime. The commit is separate from the
388	/// throwaway-prefix commit so the audit trail shows the levy step that
389	/// produced the value.
390	fn rbtdrp_install_depot_project_id(root: &Path, project_id: &str) -> Result<(), String> {
391	    let rbrr = root.join(RBTDRP_RBRR_FILE);
392	    let content = std::fs::read_to_string(&rbrr)
393	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
394	    let new_content = rbtdrp_replace_env_fields(
395	        &content,
396	        &[(RBTDRP_FIELD_RBRR_DEPOT_PROJECT_ID, project_id)],
397	    );
398	    std::fs::write(&rbrr, &new_content)
399	        .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
400	
401	    let commit_msg = format!(
402	        "pristine-lifecycle fixture: set {}={}",
403	        RBTDRP_FIELD_RBRR_DEPOT_PROJECT_ID, project_id
404	    );
405	    rbtdrp_git_add_and_commit(root, RBTDRP_RBRR_FILE, &commit_msg)
406	}
407	
408	// ── Case ─────────────────────────────────────────────────────
409	
410	/// Case 1 — marshal-zero attestation. Aggregates all five violation classes
411	/// into a single diagnostic. A passing run is the proof that `rbw-MZ` was
412	/// just executed and committed.
413	fn rbtdrp_marshal_zero_attestation(_dir: &Path) -> rbtdre_Verdict {
414	    let root = match std::env::current_dir() {
415	        Ok(r) => r,
416	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot resolve project root: {}", e)),
417	    };
418	
419	    let rbrr = root.join(RBTDRP_RBRR_FILE);
420	    if !rbrr.exists() {
421	        return rbtdre_Verdict::Fail(format!("RBRR file not found: {}", rbrr.display()));
422	    }
423	
424	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR").unwrap_or_default();
425	    let vessel_dir = rbtdrp_read_env_value(&rbrr, "RBRR_VESSEL_DIR").unwrap_or_default();
426	
427	    let mut violations: Vec<String> = Vec::new();
428	
429	    rbtdrp_check_tree_clean(&root, &mut violations);
430	    rbtdrp_check_rbrr_fields(&rbrr, &mut violations);
431	    rbtdrp_check_rbra_files(&root, &secrets_dir, &mut violations);
432	    rbtdrp_check_nameplate_hallmarks(&root, &mut violations);
433	    rbtdrp_check_vessel_depot_fields(&root, &vessel_dir, &mut violations);
434	
435	    if violations.is_empty() {
436	        return rbtdre_Verdict::Pass;
437	    }
438	
439	    let body = violations
440	        .iter()
441	        .map(|v| format!("  - {}", v))
442	        .collect::<Vec<_>>()
443	        .join("\n");
444	    rbtdre_Verdict::Fail(format!(
445	        "marshal-zero attestation failed — {} violation(s):\n{}\n\n\
446	         remedy: tt/rbw-MZ.MarshalZeroes.sh, then commit and rerun.",
447	        violations.len(),
448	        body
449	    ))
450	}
451	
452	// ── Cases 2 & 3 — depot and governor lifecycles ──────────────
453	
454	/// Wrapper invocation: call `rbtdri_invoke_global` and tee stdout/stderr to
455	/// `dir/<label>-stdout.txt` / `dir/<label>-stderr.txt` for diagnostic review.
456	/// Returns `Ok(InvokeResult)` regardless of exit code; callers decide what
457	/// counts as failure.
458	fn rbtdrp_invoke_logged(
459	    ctx: &mut rbtdri_Context,
460	    colophon: &str,
461	    args: &[&str],
462	    extra_env: &[(&str, &str)],
463	    dir: &Path,
464	    label: &str,
465	) -> Result<crate::rbtdri_invocation::rbtdri_InvokeResult, String> {
466	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
467	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
468	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
469	    Ok(result)
470	}
471	
472	/// Case 2 — depot-lifecycle. Levies a throwaway depot, asserts it appears
473	/// in `rbgp_depot_list`, soft-deletes it, then asserts it is absent or in
474	/// `DELETE_REQUESTED` state.
475	///
476	/// The depot project_id is captured from the levy invocation's
477	/// `rbgp_fact_depot_project_id` fact file rather than scraped from stdout.
478	fn rbtdrp_depot_lifecycle(dir: &Path) -> rbtdre_Verdict {
479	    rbtdrc_with_ctx(|ctx| rbtdrp_depot_lifecycle_impl(ctx, dir))
480	}
481	
482	fn rbtdrp_depot_lifecycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
483	    let root = ctx.project_root().to_path_buf();
484	
485	    if let Err(e) = rbtdrp_install_throwaway_prefixes(&root) {
486	        return rbtdre_Verdict::Fail(format!("install throwaway prefixes: {}", e));
487	    }
488	
489	    let levy = match rbtdrp_invoke_logged(
490	        ctx,
491	        RBTDRM_COLOPHON_DEPOT_LEVY,
492	        &[RBTDRP_DEPOT_MONIKER_LIFECYCLE],
493	        &[],
494	        dir,
495	        "levy",
496	    ) {
497	        Ok(r) => r,
498	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
499	    };
500	    if levy.exit_code != 0 {
501	        return rbtdre_Verdict::Fail(format!(
502	            "depot levy exit {}\n{}",
503	            levy.exit_code, levy.stderr
504	        ));
505	    }
506	
507	    let project_id = match rbtdri_read_burv_fact(&levy, RBTDRP_FACT_DEPOT_PROJECT_ID) {
508	        Ok(s) => s,
509	        Err(e) => return rbtdre_Verdict::Fail(format!("read depot project_id fact: {}", e)),
510	    };
511	    let _ = std::fs::write(dir.join("project-id.txt"), &project_id);
512	
513	    let list_present = match rbtdrp_invoke_logged(
514	        ctx,
515	        RBTDRM_COLOPHON_DEPOT_LIST,
516	        &[],
517	        &[],
518	        dir,
519	        "list-present",
520	    ) {
521	        Ok(r) => r,
522	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after levy): {}", e)),
523	    };
524	    if list_present.exit_code != 0 {
525	        return rbtdre_Verdict::Fail(format!(
526	            "depot list (after levy) exit {}\n{}",
527	            list_present.exit_code, list_present.stderr
528	        ));
529	    }
530	    if !list_present.stdout.contains(&project_id) {
531	        return rbtdre_Verdict::Fail(format!(
532	            "project_id '{}' missing from depot list after levy:\n{}",
533	            project_id, list_present.stdout
534	        ));
535	    }
536	
537	    let unmake = match rbtdrp_invoke_logged(
538	        ctx,
539	        RBTDRM_COLOPHON_DEPOT_UNMAKE,
540	        &[&project_id],
541	        &[(RBTDRP_BURE_CONFIRM_KEY, RBTDRP_BURE_CONFIRM_SKIP)],
542	        dir,
543	        "unmake",
544	    ) {
545	        Ok(r) => r,
546	        Err(e) => return rbtdre_Verdict::Fail(format!("depot unmake: {}", e)),
547	    };
548	    if unmake.exit_code != 0 {
549	        return rbtdre_Verdict::Fail(format!(
550	            "depot unmake exit {}\n{}",
551	            unmake.exit_code, unmake.stderr
552	        ));
553	    }
554	
555	    let list_after = match rbtdrp_invoke_logged(
556	        ctx,
557	        RBTDRM_COLOPHON_DEPOT_LIST,
558	        &[],
559	        &[],
560	        dir,
561	        "list-after",
562	    ) {
563	        Ok(r) => r,
564	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after unmake): {}", e)),
565	    };
566	    if list_after.exit_code != 0 {
567	        return rbtdre_Verdict::Fail(format!(
568	            "depot list (after unmake) exit {}\n{}",
569	            list_after.exit_code, list_after.stderr
570	        ));
571	    }
572	    for line in list_after.stdout.lines() {
573	        if line.contains(&project_id) && !line.contains(RBTDRP_DELETE_REQUESTED) {
574	            return rbtdre_Verdict::Fail(format!(
575	                "project_id '{}' still present without {} after unmake:\n{}",
576	                project_id, RBTDRP_DELETE_REQUESTED, line
577	            ));
578	        }
579	    }
580	
581	    rbtdre_Verdict::Pass
582	}
583	
584	/// Case 3 — governor-lifecycle. Levies its own throwaway depot (so
585	/// `RBRR_DEPOT_PROJECT_ID` becomes set, satisfying the precondition for
586	/// `rbgp_governor_mantle`), mantles a governor, asserts it appears in
587	/// `rbgg_list_service_accounts`, forfeits it, asserts absent, then unmakes
588	/// the depot to clean up.
589	///
590	/// Governor lifecycle uses a moniker distinct from case 2 so both cases'
591	/// depots are separable when the full fixture runs.
592	fn rbtdrp_governor_lifecycle(dir: &Path) -> rbtdre_Verdict {
593	    rbtdrc_with_ctx(|ctx| rbtdrp_governor_lifecycle_impl(ctx, dir))
594	}
595	
596	fn rbtdrp_governor_lifecycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
597	    let root = ctx.project_root().to_path_buf();
598	
599	    if let Err(e) = rbtdrp_install_throwaway_prefixes(&root) {
600	        return rbtdre_Verdict::Fail(format!("install throwaway prefixes: {}", e));
601	    }
602	
603	    let levy = match rbtdrp_invoke_logged(
604	        ctx,
605	        RBTDRM_COLOPHON_DEPOT_LEVY,
606	        &[RBTDRP_DEPOT_MONIKER_GOVERNOR],
607	        &[],
608	        dir,
609	        "levy",
610	    ) {
611	        Ok(r) => r,
612	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
613	    };
614	    if levy.exit_code != 0 {
615	        return rbtdre_Verdict::Fail(format!(
616	            "depot levy exit {}\n{}",
617	            levy.exit_code, levy.stderr
618	        ));
619	    }
620	
621	    let project_id = match rbtdri_read_burv_fact(&levy, RBTDRP_FACT_DEPOT_PROJECT_ID) {
622	        Ok(s) => s,
623	        Err(e) => return rbtdre_Verdict::Fail(format!("read depot project_id fact: {}", e)),
624	    };
625	    let _ = std::fs::write(dir.join("project-id.txt"), &project_id);
626	
627	    if let Err(e) = rbtdrp_install_depot_project_id(&root, &project_id) {
628	        return rbtdre_Verdict::Fail(format!("set RBRR_DEPOT_PROJECT_ID: {}", e));
629	    }
630	
631	    let mantle = match rbtdrp_invoke_logged(
632	        ctx,
633	        RBTDRM_COLOPHON_GOV_MANTLE,
634	        &[],
635	        &[],
636	        dir,
637	        "mantle",
638	    ) {
639	        Ok(r) => r,
640	        Err(e) => return rbtdre_Verdict::Fail(format!("governor mantle: {}", e)),
641	    };
642	    if mantle.exit_code != 0 {
643	        return rbtdre_Verdict::Fail(format!(
644	            "governor mantle exit {}\n{}",
645	            mantle.exit_code, mantle.stderr
646	        ));
647	    }
648	
649	    let sa_email = match rbtdri_read_burv_fact(&mantle, RBTDRP_FACT_GOVERNOR_SA_EMAIL) {
650	        Ok(s) => s,
651	        Err(e) => return rbtdre_Verdict::Fail(format!("read governor SA email fact: {}", e)),
652	    };
653	    let _ = std::fs::write(dir.join("sa-email.txt"), &sa_email);
654	
655	    let list_present = match rbtdrp_invoke_logged(
656	        ctx,
657	        RBTDRM_COLOPHON_GOV_LIST_SAS,
658	        &[],
659	        &[],
660	        dir,
661	        "list-present",
662	    ) {
663	        Ok(r) => r,
664	        Err(e) => return rbtdre_Verdict::Fail(format!("list SAs (after mantle): {}", e)),
665	    };
666	    if list_present.exit_code != 0 {
667	        return rbtdre_Verdict::Fail(format!(
668	            "list SAs (after mantle) exit {}\n{}",
669	            list_present.exit_code, list_present.stderr
670	        ));
671	    }
672	    if !list_present.stdout.contains(&sa_email) {
673	        return rbtdre_Verdict::Fail(format!(
674	            "governor SA '{}' missing from list after mantle:\n{}",
675	            sa_email, list_present.stdout
676	        ));
677	    }
678	
679	    let forfeit = match rbtdrp_invoke_logged(
680	        ctx,
681	        RBTDRM_COLOPHON_GOV_FORFEIT,
682	        &[&sa_email],
683	        &[],
684	        dir,
685	        "forfeit",
686	    ) {
687	        Ok(r) => r,
688	        Err(e) => return rbtdre_Verdict::Fail(format!("governor forfeit: {}", e)),
689	    };
690	    if forfeit.exit_code != 0 {
691	        return rbtdre_Verdict::Fail(format!(
692	            "governor forfeit exit {}\n{}",
693	            forfeit.exit_code, forfeit.stderr
694	        ));
695	    }
696	
697	    let list_after = match rbtdrp_invoke_logged(
698	        ctx,
699	        RBTDRM_COLOPHON_GOV_LIST_SAS,
700	        &[],
701	        &[],
702	        dir,
703	        "list-after",
704	    ) {
705	        Ok(r) => r,
706	        Err(e) => return rbtdre_Verdict::Fail(format!("list SAs (after forfeit): {}", e)),
707	    };
708	    if list_after.exit_code != 0 {
709	        return rbtdre_Verdict::Fail(format!(
710	            "list SAs (after forfeit) exit {}\n{}",
711	            list_after.exit_code, list_after.stderr
712	        ));
713	    }
714	    if list_after.stdout.contains(&sa_email) {
715	        return rbtdre_Verdict::Fail(format!(
716	            "governor SA '{}' still present after forfeit:\n{}",
717	            sa_email, list_after.stdout
718	        ));
719	    }
720	
721	    let unmake = match rbtdrp_invoke_logged(
722	        ctx,
723	        RBTDRM_COLOPHON_DEPOT_UNMAKE,
724	        &[&project_id],
725	        &[(RBTDRP_BURE_CONFIRM_KEY, RBTDRP_BURE_CONFIRM_SKIP)],
726	        dir,
727	        "unmake",
728	    ) {
729	        Ok(r) => r,
730	        Err(e) => return rbtdre_Verdict::Fail(format!("depot unmake (cleanup): {}", e)),
731	    };
732	    if unmake.exit_code != 0 {
733	        return rbtdre_Verdict::Fail(format!(
734	            "depot unmake (cleanup) exit {}\n{}",
735	            unmake.exit_code, unmake.stderr
736	        ));
737	    }
738	
739	    rbtdre_Verdict::Pass
740	}
741	
742	// ── Section registry ─────────────────────────────────────────
743	
744	pub static RBTDRP_SECTIONS_PRISTINE_LIFECYCLE: &[rbtdre_Section] = &[
745	    rbtdre_Section {
746	        name: "pristine-lifecycle-gate",
747	        cases: &[case!(rbtdrp_marshal_zero_attestation)],
748	    },
